# 1. Rule-based classifier
def can_fly_rules(animal):
    known = {
        "eagle": True,
        "sparrow": True,
        "bat": True,
        "dog": False,
        "cat": False,
        "penguin": False,
    }
    return known.get(animal.lower(), False)

# 2. Feature-based classifier
def simple_ml_classify(features):
    return all(f == 1 for f in features)

print(can_fly_rules("eagle"))         # True
print(can_fly_rules("dog"))           # False
print(can_fly_rules("unicorn"))       # False (unknown -> default)
print(simple_ml_classify([1, 1]))     # True
print(simple_ml_classify([1, 0]))     # False
print(simple_ml_classify([0, 1]))     # False
